const allMessages = [];

for (const item of $input.all()) {
  const thread = item.json;

  if (thread && Array.isArray(thread.messages)) {
    const messagesFromThisThread = thread.messages.map(msg => {
      return {
        json: {
          messageId: msg.id,
          threadId: msg.threadId
        }
      };
    });
    allMessages.push(...messagesFromThisThread);
  }
}

return allMessages;

const threadsMap = new Map();

for (const item of $input.all()) {
  const message = item.json;
  const threadId = message.threadId;

  if (!threadId) continue;

  if (threadsMap.has(threadId)) {
    threadsMap.get(threadId).messages.push(message);
  } else {
    threadsMap.set(threadId, {
      threadId: threadId,
      messages: [message]
    });
  }
}

for (const thread of threadsMap.values()) {
  thread.messages.sort((a, b) => {
    return parseInt(a.internalDate) - parseInt(b.internalDate);
  });
}

const finalThreads = Array.from(threadsMap.values());
return finalThreads.map(thread => ({ json: thread }));

const thread = $json;

if (!thread?.messages?.[0]?.from?.value?.[0]?.address) {
  return {
    json: {
      error: "Invalid message structure or missing sender address.",
      threadId: thread?.threadId || 'unknown'
    }
  };
}

// Configure your support email domains here
const supportDomains = ['support@yourcompany.com', '@yourcompany.com'];

function isSupport(email) {
  return supportDomains.some(domain => email.includes(domain));
}

function getCleanText(text) {
  if (!text) return '';
  const splitters = [
    '\nOn ',
    '\nEl ',
    '\n\n-----Original Message-----',
    '\n\n-----Mensaje original-----',
    '\nFrom: ',
  ];
  let cleanText = text;
  for (const splitter of splitters) {
    const position = cleanText.indexOf(splitter);
    if (position > 0) {
      cleanText = cleanText.substring(0, position);
    }
  }
  return cleanText.trim();
}

const conversationHistory = thread.messages.map(message => {
  const currentSenderEmail = message?.from?.value?.[0]?.address;
  const rawBody = message.text || '';
  const cleanBody = getCleanText(rawBody);
  const role = isSupport(currentSenderEmail) ? 'support' : 'user';
  return {
    role,
    content: cleanBody,
    timestamp: message.date || message.timestamp || new Date().toISOString()
  };
});

const firstSenderEmail = thread.messages[0].from.value[0].address;
const initiatedBy = isSupport(firstSenderEmail) ? 'support' : 'user';

const clientEmails = thread.messages
  .map(m => m.from.value[0].address)
  .filter(email => !isSupport(email));
const identifiedUser = clientEmails[0] || firstSenderEmail;

return {
  json: {
    threadId: thread.threadId,
    subject: thread.subject || thread.messages[0]?.subject || 'No subject',
    initiatedBy: initiatedBy,
    identifiedUser: identifiedUser,
    conversationHistory: conversationHistory
  }
};

return $input.all().map(item => {
  const { output, ...rest } = item.json;
  return {
    json: {
      ...rest,
      area: {
        description: output.area,
        sub_area: output.sub_area,
        confidence: output.confidence
      }
    }
  };
});

options.systemMessage:
Classify user intent in support emails.

INTENTS:
how_to: Learn how to do something
not_working: Something broken/error
information: What/where is something
other: Unclear intent

RULES: One intent | Confidence 0.0-1.0 | <0.6=other

EXAMPLES:
"How do I configure X?" -> {"intent":"how_to","confidence":0.95}
"Getting an error when saving" -> {"intent":"not_working","confidence":0.95}
"Where can I find the settings?" -> {"intent":"information","confidence":0.9}
"Hello" -> {"intent":"other","confidence":0.3}

OUTPUT: {"intent":"string","confidence":0.0-1.0}

