// Build search query from area classification
const item = $json;
const area = item.area?.description || 'general';
const subAreas = item.area?.sub_area || [];
const searchQuery = subAreas.length > 0
  ? `${area}-${subAreas[0]}`
  : area;

return [{
  json: {
    ...item,
    searchQuery: searchQuery
  }
}];

